import mongoose, { Schema, Document } from 'mongoose';

export interface IAnnouncement extends Document {
  title: string;
  content: string;
  target_group: 'ALL' | 'STUDENT' | 'TEACHER' | 'STAFF';
  channels: ('APP' | 'EMAIL' | 'SMS')[];
  status: 'SENT' | 'SCHEDULED';
  scheduled_at?: Date;
  created_by?: mongoose.Types.ObjectId;
  createdAt: Date;
  updatedAt: Date;
}

const AnnouncementSchema: Schema = new Schema(
  {
    title: { type: String, required: true },
    content: { type: String, required: true },
    target_group: {
      type: String,
      enum: ['ALL', 'STUDENT', 'TEACHER', 'STAFF'],
      default: 'ALL',
    },
    channels: [
      {
        type: String,
        enum: ['APP', 'EMAIL', 'SMS'],
      },
    ],
    status: {
      type: String,
      enum: ['SENT', 'SCHEDULED'],
      default: 'SENT',
    },
    scheduled_at: { type: Date },
    created_by: { type: Schema.Types.ObjectId, ref: 'Users' },
  },
  { timestamps: true, collection: 'announcements' },
);

export const AnnouncementModel = mongoose.model<IAnnouncement>('Announcement', AnnouncementSchema);
export default AnnouncementModel;
import mongoose, { Schema, Document } from 'mongoose';

export interface ICity extends Document {
  name: string;
  code: string;
  created_at: Date;
  updated_at: Date;
}

const CitySchema = new Schema<ICity>(
  {
    name: { type: String, required: true },
    code: { type: String, required: true, unique: true },
  },
  {
    timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
    versionKey: false,
    collection: 'cities',
  },
);

export const CityModel = mongoose.models.Cities || mongoose.model<ICity>('Cities', CitySchema, 'cities');
import mongoose, { Schema, Document, Types } from 'mongoose';

export interface ICourseFeeStage {
  name: string;
  amount: number;
}

export interface ICourse extends Document {
  license_category_id?: Types.ObjectId | null;
  code: string; // Mã nội bộ của trung tâm
  name: string; // Tên khóa học
  system_course_id?: number;
  system_course_code?: string; // Mã báo cáo lên Sở GTVT
  curriculum_id?: number;
  management_record_number?: string;
  description?: string;
  report_start_date?: Date;
  start_date?: Date;
  end_date?: Date;
  dat_date?: Date; // Ngày tập trung chạy DAT
  cabin_date?: Date; // Ngày học Cabin
  decision_to_sign?: string;
  duration?: number;
  status: 'draft' | 'ongoing' | 'completed' | 'canceled';
  course_fee?: number;
  max_students?: number;
  teacher_id?: Types.ObjectId | null;

  // Extension for Web Admin
  internal_note?: string;
  note?: string;
  course_type?: string;
  fee_stages?: ICourseFeeStage[];
  created_at: Date;
  updated_at: Date;
}

const CourseSchema = new Schema<ICourse>(
  {
    license_category_id: { type: Schema.Types.ObjectId, ref: 'LicenseCategories', default: null },
    code: { type: String, required: true, unique: true, index: true },
    name: { type: String, required: true },
    system_course_id: { type: Number },
    system_course_code: { type: String },
    curriculum_id: { type: Number },
    management_record_number: { type: String },
    description: { type: String },
    report_start_date: { type: Date },
    start_date: { type: Date },
    end_date: { type: Date },
    dat_date: { type: Date },
    cabin_date: { type: Date },
    decision_to_sign: { type: String },
    duration: { type: Number },
    status: {
      type: String,
      enum: ['draft', 'ongoing', 'completed', 'canceled'],
      default: 'draft',
    },
    course_fee: { type: Number, default: 0 },
    max_students: { type: Number, default: 50 },
    teacher_id: { type: Schema.Types.ObjectId, ref: 'Users', index: true, default: null },
    internal_note: { type: String },
    note: { type: String },
    course_type: { type: String, default: 'trực tiếp' },
    fee_stages: [
      {
        name: { type: String },
        amount: { type: Number, default: 0 },
      },
    ],
  },
  {
    timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
    versionKey: false,
    collection: 'courses',
  },
);

CourseSchema.index({ status: 1 });
CourseSchema.index({ start_date: -1 });

if (mongoose.models.Courses) {
  mongoose.deleteModel('Courses');
}
export const CourseModel = mongoose.model<ICourse>('Courses', CourseSchema, 'courses');
import mongoose, { Schema, Document, Types } from 'mongoose';

export interface ICourseStudent extends Document {
  student_id: Types.ObjectId; // References Student(student_infos)
  course_id: Types.ObjectId; // References Course(course_infos)
  stadium_id?: Types.ObjectId | null;
  teacher_id?: Types.ObjectId | null;
  sale_id?: Types.ObjectId | null;
  license_category_id?: Types.ObjectId | null;
  status: 'unfinished' | 'finished' | 'canceled';
  km: number;
  hour: string;
  fee: number;
  paid_fee: number;
  balance?: any; // Treasury balance for this enrollment
  contract_date?: Date | null;
  status_detail?: string;
  progress_flags?: {
    theory_completed: boolean;
    sand_yard_completed: boolean;
    simulation_completed: boolean;
    dat_completed: boolean;
    cabin_completed: boolean;
    graduation_eligible: boolean;
  };
  health_check?: {
    status: string;
    date: Date | null;
    hospital: string | null;
    note: string | null;
  };
  created_at: Date;
  updated_at: Date;
}

const CourseStudentSchema = new Schema<ICourseStudent>(
  {
    student_id: { type: Schema.Types.ObjectId, ref: 'StudentInfos', required: true, index: true },
    course_id: { type: Schema.Types.ObjectId, ref: 'Courses', required: true, index: true },
    stadium_id: { type: Schema.Types.ObjectId, ref: 'Stadiums', default: null },
    teacher_id: { type: Schema.Types.ObjectId, ref: 'Users', default: null },
    sale_id: { type: Schema.Types.ObjectId, ref: 'Users', default: null },
    license_category_id: { type: Schema.Types.ObjectId, ref: 'LicenseCategories', default: null },
    status: {
      type: String,
      enum: ['unfinished', 'finished', 'canceled'],
      default: 'unfinished',
    },
    km: { type: Number, default: 0 },
    hour: { type: String, default: '00:00' },
    fee: { type: Number, default: 0 },
    paid_fee: { type: Number, default: 0 },
    balance: {
      type: Schema.Types.Decimal128,
      default: 0,
      get: (v: any) => (v ? parseFloat(v.toString()) : 0),
    },
    contract_date: { type: Date, default: null },
    status_detail: { type: String, default: 'Chờ KSK' },
    progress_flags: {
      theory_completed: { type: Boolean, default: false },
      sand_yard_completed: { type: Boolean, default: false },
      simulation_completed: { type: Boolean, default: false },
      dat_completed: { type: Boolean, default: false },
      cabin_completed: { type: Boolean, default: false },
      graduation_eligible: { type: Boolean, default: false },
    },
    health_check: {
      status: { type: String, enum: ['Chờ khám', 'Đủ điều kiện', 'Không đủ điều kiện'], default: 'Chờ khám' },
      date: { type: Date, default: null },
      hospital: { type: String, default: null },
      note: { type: String, default: null },
    },
  },
  {
    timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
    versionKey: false,
    collection: 'coursestudents',
  },
);

CourseStudentSchema.index({ student_id: 1, created_at: -1 });
CourseStudentSchema.index({ course_id: 1, created_at: -1 });
CourseStudentSchema.index({ status_detail: 1, created_at: -1 });
CourseStudentSchema.index({ sale_id: 1, created_at: -1 });
CourseStudentSchema.index({ 'progress_flags.dat_completed': 1, status_detail: 1 });
CourseStudentSchema.index({ fee: 1, paid_fee: 1 });

export const CourseStudentModel =
  mongoose.models.CourseStudents ||
  mongoose.model<ICourseStudent>('CourseStudents', CourseStudentSchema, 'coursestudents');
import mongoose, { Schema, Document, Types } from 'mongoose';

export enum DatSessionType {
  Cabin = 'cabin',
  Dat = 'dat',
}

export interface IDatSession extends Document {
  course_student_id: Types.ObjectId;
  session_type: DatSessionType;
  start_time: Date;
  end_time: Date;
  distance_km: number;
  rfid_card?: string;
  notes?: string;
  created_at: Date;
  updated_at: Date;
}

const DatSessionSchema = new Schema<IDatSession>(
  {
    course_student_id: { type: Schema.Types.ObjectId, ref: 'CourseStudents', required: true, index: true },
    session_type: { type: String, enum: Object.values(DatSessionType), required: true },
    start_time: { type: Date, required: true },
    end_time: { type: Date, required: true },
    distance_km: { type: Number, required: true, default: 0 },
    rfid_card: { type: String },
    notes: { type: String },
  },
  {
    timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
    versionKey: false,
  },
);

DatSessionSchema.index({ session_type: 1 });
DatSessionSchema.index({ start_time: -1 });

export const DatSessionModel =
  mongoose.models.DatSession || mongoose.model<IDatSession>('DatSession', DatSessionSchema);
import mongoose, { Schema, Document, Types } from 'mongoose';

export enum ExamType {
  Graduation = 'graduation',
  SatHach = 'sat_hach',
}

export enum ExamResult {
  Pass = 'pass',
  Fail = 'fail',
  NoResult = 'no_result',
}

export interface IExamTypeResult {
  result: string;
  name: string;
  lesson_type_id?: string;
  description?: string;
}

export interface IExam extends Document {
  course_student_id?: Types.ObjectId | null;
  exam_types?: Map<string, IExamTypeResult>;
  stadium_id?: Types.ObjectId | null;
  license_category_id?: Types.ObjectId | null;
  parent_id?: Types.ObjectId | null;

  name: string;
  status: string;
  exam_type: ExamType;

  start_time?: Date;
  end_time?: Date;

  description?: string;
  session?: string;
  exam_number?: number;

  is_pickup: boolean;
  pickup_point?: string;
  location?: string;
  result: ExamResult;
  registration_number?: string;
  studentResults?: any[];
  teacher_id?: Types.ObjectId | null;

  created_at: Date;
  updated_at: Date;
}

const IExamTypeResultSchema = new Schema(
  {
    result: { type: String },
    name: { type: String },
    lesson_type_id: { type: String },
    description: { type: String },
  },
  { _id: false },
);

const ExamSchema = new Schema<IExam>(
  {
    course_student_id: { type: Schema.Types.ObjectId, ref: 'CourseStudents', index: true },
    exam_types: {
      type: Map,
      of: IExamTypeResultSchema,
    },
    stadium_id: { type: Schema.Types.ObjectId, ref: 'Stadiums' },
    license_category_id: { type: Schema.Types.ObjectId, ref: 'LicenseCategories' },
    parent_id: { type: Schema.Types.ObjectId, ref: 'Exams', default: null },

    name: { type: String, required: true, trim: true },
    status: { type: String, trim: true },
    exam_type: { type: String, enum: Object.values(ExamType), required: true },

    start_time: { type: Date, index: true },
    end_time: { type: Date },

    description: { type: String, default: '' },
    session: { type: String },
    exam_number: { type: Number },

    is_pickup: { type: Boolean, default: false },
    pickup_point: { type: String },
    location: { type: String },
    result: { type: String, enum: Object.values(ExamResult), default: ExamResult.NoResult },
    registration_number: { type: String },
    studentResults: [{ type: Schema.Types.Mixed }],
    teacher_id: { type: Schema.Types.ObjectId, ref: 'Users', index: true },
  },
  {
    timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
    versionKey: false,
  },
);

ExamSchema.index({ exam_type: 1 });
ExamSchema.index({ stadium_id: 1 });

export const ExamModel = mongoose.models.Exams || mongoose.model<IExam>('Exams', ExamSchema);
import mongoose, { Schema, Document, Types } from 'mongoose';

export interface IExamBatch extends Document {
  name: string;
  vehicleType: string;
  region: string;
  examDate: Date;
  officialDate?: Date;
  venue: string;
  stadium_id?: string;
  status: 'upcoming' | 'confirmed' | 'completed' | 'cancelled';
  studentResults: any[];
  teacher_id?: Types.ObjectId | null;
  created_at: Date;
  updated_at: Date;
}

const ExamBatchSchema = new Schema<IExamBatch>(
  {
    name: { type: String, required: true, trim: true },
    vehicleType: { type: String, required: true, trim: true },
    region: { type: String, required: true, trim: true },
    examDate: { type: Date, required: true },
    officialDate: { type: Date },
    venue: { type: String, required: true, trim: true },
    stadium_id: { type: String, trim: true },
    status: {
      type: String,
      enum: ['upcoming', 'confirmed', 'completed', 'cancelled'],
      default: 'upcoming',
    },
    studentResults: [{ type: Schema.Types.Mixed }],
    teacher_id: { type: Schema.Types.ObjectId, ref: 'Users', index: true },
  },
  {
    timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
    versionKey: false,
  },
);

ExamBatchSchema.index({ name: 1 });
ExamBatchSchema.index({ status: 1 });
ExamBatchSchema.index({ examDate: 1 });

const ExamBatchModel = mongoose.models.ExamBatch || mongoose.model<IExamBatch>('ExamBatch', ExamBatchSchema);

export default ExamBatchModel;
import mongoose, { Schema, Document, Types } from 'mongoose';

export interface IExamSchedule extends Document {
  exam_id: Types.ObjectId;
  start_time: Date;
  end_time: Date;
  note?: string;
  created_at: Date;
  updated_at: Date;
}

const ExamScheduleSchema = new Schema<IExamSchedule>(
  {
    exam_id: { type: Schema.Types.ObjectId, ref: 'Exams', required: true, index: true },
    start_time: { type: Date, required: true },
    end_time: { type: Date, required: true },
    note: { type: String, default: '' },
  },
  {
    timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
    versionKey: false,
    collection: 'examschedules',
  },
);

ExamScheduleSchema.index({ start_time: -1 });
ExamScheduleSchema.index({ start_time: 1, end_time: 1 });

export const ExamScheduleModel =
  mongoose.models.ExamSchedules || mongoose.model<IExamSchedule>('ExamSchedules', ExamScheduleSchema, 'examschedules');
