import mongoose, { Schema, Document, Types } from 'mongoose';

export enum LessonStatus {
  Pending = 'pending',
  InProgress = 'in_progress',
  Completed = 'completed',
  NoTeacher = 'no_teacher',
  CanceledClass = 'canceled_class',
  DroppedClass = 'dropped_class',
  Deleted = 'deleted',
}

export enum LessonCategory {
  Theory = 'theory',
  Practice = 'practice',
}

export interface ILesson extends Document {
  course_student_id?: Types.ObjectId;
  student_id?: Types.ObjectId; // References User(student)
  teacher_id?: Types.ObjectId; // References User(teacher)
  name: string;
  category: LessonCategory;
  status: LessonStatus;
  start_time: Date;
  end_time: Date;
  description?: string;
  lesson_type_id?: Types.ObjectId;
  vehicle_id?: Types.ObjectId;
  is_night_course: boolean;
  is_automatic_course: boolean;
  km: number;
  hour: string;
  vehicle_type?: string;
  stadium_id?: Types.ObjectId;
  order: number;
  confirmed: boolean;
  pickup_point?: string;
  is_pickup: boolean;
  created_at: Date;
  updated_at: Date;
}

const LessonSchema = new Schema<ILesson>(
  {
    course_student_id: { type: Schema.Types.ObjectId, ref: 'CourseStudents', index: true },
    student_id: { type: Schema.Types.ObjectId, ref: 'Users', index: true },
    teacher_id: { type: Schema.Types.ObjectId, ref: 'Users', index: true },
    name: { type: String, required: true },
    category: {
      type: String,
      enum: Object.values(LessonCategory),
      default: LessonCategory.Practice,
      required: true,
    },
    status: {
      type: String,
      enum: Object.values(LessonStatus),
      default: LessonStatus.Pending,
      required: true,
    },
    start_time: { type: Date, required: true, index: true },
    end_time: { type: Date, required: true },
    description: { type: String, default: '' },
    lesson_type_id: { type: Schema.Types.ObjectId },
    vehicle_id: { type: Schema.Types.ObjectId },
    is_night_course: { type: Boolean, default: false },
    is_automatic_course: { type: Boolean, default: false },
    km: { type: Number, default: 0 },
    hour: { type: String, default: '00:00' },
    vehicle_type: { type: String, enum: ['car', 'motorbike'] },
    stadium_id: { type: Schema.Types.ObjectId, ref: 'Stadiums' },
    order: { type: Number, default: 1 },
    confirmed: { type: Boolean, default: false },
    pickup_point: { type: String },
    is_pickup: { type: Boolean, default: false },
  },
  {
    timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
    versionKey: false,
  },
);

export const LessonModel = mongoose.models.Lessons || mongoose.model<ILesson>('Lessons', LessonSchema);
import mongoose, { Schema, Document } from 'mongoose';

export interface ILicenseCategory extends Document {
  name: string;
  code: string;
  description?: string;
  type: 'Ô tô' | 'Xe máy';
  fee: string;
  tags: string[];
  inactive: string[];
  dat?: string | null;
  created_at: Date;
  updated_at: Date;
}

const LicenseCategorySchema = new Schema<ILicenseCategory>(
  {
    name: { type: String, required: true },
    code: { type: String, required: true, unique: true },
    description: { type: String },
    type: { type: String, enum: ['Ô tô', 'Xe máy'], default: 'Ô tô' },
    fee: { type: String, default: '0đ' },
    tags: { type: [String], default: [] },
    inactive: { type: [String], default: [] },
    dat: { type: String, default: null },
  },
  {
    timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
    versionKey: false,
    collection: 'licensecategories',
  },
);

if (mongoose.models.LicenseCategories) {
  mongoose.deleteModel('LicenseCategories');
}
export const LicenseCategoryModel = mongoose.model<ILicenseCategory>(
  'LicenseCategories',
  LicenseCategorySchema,
  'licensecategories',
);
import mongoose, { Schema, Document, Types } from 'mongoose';

export interface INotification extends Document {
  config_id?: Types.ObjectId; // Referencing notification config/template
  content_id?: Types.ObjectId; // Referencing the actual content
  is_read: boolean;
  receive_id: Types.ObjectId; // The recipient User ID
  receive_type: 'user' | 'student' | 'teacher';
  category?: 'notif' | 'system';

  // Extension for direct notification if not using config_id/content_id
  title?: string;
  body?: string;
  data?: any; // Extra payload for FCM

  created_at: Date;
  updated_at: Date;
}

const NotificationSchema = new Schema<INotification>(
  {
    config_id: { type: Schema.Types.ObjectId, ref: 'NotifyConfigs', index: true },
    content_id: { type: Schema.Types.ObjectId, ref: 'NotifyContents' },
    is_read: { type: Boolean, default: false },
    receive_id: { type: Schema.Types.ObjectId, ref: 'Users', required: true, index: true },
    receive_type: {
      type: String,
      enum: ['user', 'student', 'teacher'],
      default: 'user',
    },
    category: {
      type: String,
      enum: ['notif', 'system'],
      default: 'notif',
    },
    title: { type: String },
    body: { type: String },
    data: { type: Schema.Types.Mixed },
  },
  {
    timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
    versionKey: false,
  },
);

NotificationSchema.index({ created_at: -1 });

export const NotificationModel =
  mongoose.models.Notification || mongoose.model<INotification>('Notification', NotificationSchema);
/**
 * notifies — aligned to ahv-driving-training reference.
 * Collection name: "notifies" (plural, all lowercase).
 * Bootstrap-backup fields moved to notifyContents.data.
 */
import mongoose, { Schema, Document, Model, Types } from 'mongoose';

export const INotifyStatus = {
  Draft: 'draft',
  Sent: 'sent',
  Cancel: 'cancel',
} as const;
export type NotifyStatus = (typeof INotifyStatus)[keyof typeof INotifyStatus];

export interface INotify extends Document {
  content_id: Types.ObjectId;
  config_id: Types.ObjectId;
  status: NotifyStatus;
  created_at: Date;
  updated_at: Date;
}

const NotifySchema = new Schema<INotify>(
  {
    content_id: {
      type: Schema.Types.ObjectId,
      ref: 'NotifyContent',
      required: [true, 'content_id is required'],
      index: true,
    },
    config_id: {
      type: Schema.Types.ObjectId,
      ref: 'NotifyConfigs',
      required: [true, 'config_id is required'],
      index: true,
    },
    status: {
      type: String,
      enum: Object.values(INotifyStatus),
      default: 'draft',
      required: [true, 'status is required'],
    },
  },
  {
    timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
    versionKey: false,
    toJSON: {
      virtuals: true,
      transform: (_doc, ret: Record<string, unknown>) => {
        ret.id = ret._id;
        delete ret._id;
        return ret;
      },
    },
    toObject: {
      virtuals: true,
      transform: (_doc, ret: Record<string, unknown>) => {
        ret.id = ret._id;
        delete ret._id;
        return ret;
      },
    },
  },
);

NotifySchema.index({ created_at: -1, status: 1 });

const Notify: Model<INotify> = mongoose.models.notifies || mongoose.model<INotify>('notifies', NotifySchema);

export default Notify;
/**
 * NotifyConfigs — aligned to ahv-driving-training reference.
 * Exact field names preserved. Used as required config_id in notifies.
 */
import mongoose, { Schema, Document, Model } from 'mongoose';

export const INotifyChannelConfig = {
  Telegram: 'Telegram',
  Zalo: 'Zalo',
  CMS: 'CMS',
  Mobile: 'Mobile',
} as const;
export type NotifyChannelConfig = (typeof INotifyChannelConfig)[keyof typeof INotifyChannelConfig];

export interface INotifyConfig extends Document {
  name: string | null;
  channel: NotifyChannelConfig;
  channel_config: Record<string, unknown>;
  schedule_config: { time?: string; days?: number[] } | null;
  api_config: Record<string, unknown>;
  active: boolean;
  is_schedule: boolean;
  created_at: Date;
  updated_at: Date;
}

const NotifyConfigSchema = new Schema<INotifyConfig>(
  {
    name: { type: String, default: null, trim: true },
    channel: {
      type: String,
      enum: Object.values(INotifyChannelConfig),
