import { Router } from 'express';
import authRoutes from './auth.routes';
import studentRoutes from './student.routes';
import courseRoutes from './course.routes';
import examRoutes from './exam.routes';
import paymentRoutes from './payment.routes';
import examBatchRoutes from './exam_batch.routes';
import vipQrRoutes from './vip_qr.routes';
import notificationRoutes from './notification.routes';
import settingsRoutes from './settings.routes';
import licenseCategoryRoutes from './license-category.routes';
import stadiumRoutes from './stadium.routes';
import dashboardRoutes from './dashboard.routes';
import cityRoutes from './city.routes';
import datRoutes from './dat.routes';
import announcementRoutes from './announcement.routes';
import examScheduleRoutes from './exam_schedule.routes';
import lessonRoutes from './lesson.routes';
import dataRoutes from './data.routes';
import supportRequestRoutes from './support_request.route';
import { Role } from '@/domain/constants/rbac';
import { authenticateJWT } from '@/interface/middlewares/auth.middleware';
import { systemLogMiddleware } from '@/interface/middlewares/system_log.middleware';
import { authRateLimit } from '@/interface/middlewares/rate-limit.middleware';
import { rbacMiddleware as rbacGuard, moduleAccessGuard } from '@/interface/middlewares/rbac.middleware';

const router = Router();

// Public Routes
router.get('/health', (req, res) => {
  res.status(200).json({
    status: 'ok',
    timestamp: new Date().toISOString(),
    uptime: process.uptime(),
  });
});

router.use('/auth', authRateLimit, authRoutes);

// Protected Routes (JWT and Audit Logging)
router.use(authenticateJWT, systemLogMiddleware);

// --- Module Access Control ---

// Strictly Superadmin-only modules
router.use('/data', rbacGuard([Role.SUPERADMIN]), dataRoutes);

// Shared and Private modules (Accessible by Teacher + Admin)
router.use('/students', rbacGuard([Role.SUPERADMIN, Role.TEACHER]), studentRoutes);
router.use('/courses', rbacGuard([Role.SUPERADMIN, Role.TEACHER]), courseRoutes);
router.use('/exams', rbacGuard([Role.SUPERADMIN, Role.TEACHER]), examRoutes);
router.use('/exam-batches', rbacGuard([Role.SUPERADMIN, Role.TEACHER]), examBatchRoutes);
router.use('/exam-schedules', rbacGuard([Role.SUPERADMIN, Role.TEACHER]), examScheduleRoutes);
router.use('/lessons', rbacGuard([Role.SUPERADMIN, Role.TEACHER]), lessonRoutes);
router.use('/payments', rbacGuard([Role.SUPERADMIN, Role.TEACHER]), paymentRoutes);
router.use('/vip-qr', rbacGuard([Role.SUPERADMIN, Role.TEACHER]), vipQrRoutes);
router.use('/notifications', rbacGuard([Role.SUPERADMIN, Role.TEACHER]), notificationRoutes);
router.use('/settings', rbacGuard([Role.SUPERADMIN, Role.TEACHER]), settingsRoutes);
router.use('/license-categories', rbacGuard([Role.SUPERADMIN, Role.TEACHER]), licenseCategoryRoutes);
router.use('/stadiums', rbacGuard([Role.SUPERADMIN, Role.TEACHER]), stadiumRoutes);
router.use('/dashboard', rbacGuard([Role.SUPERADMIN, Role.TEACHER]), dashboardRoutes);
router.use('/cities', rbacGuard([Role.SUPERADMIN, Role.TEACHER]), cityRoutes);
router.use('/dat', rbacGuard([Role.SUPERADMIN, Role.TEACHER]), datRoutes);
router.use('/announcements', rbacGuard([Role.SUPERADMIN, Role.TEACHER]), announcementRoutes);
router.use('/support-requests', supportRequestRoutes); // RBAC handled inside route

export default router;

