import express from 'express';
import * as notifyController from '@/interface/controllers/notify.controller';
import { paginationMiddleware } from '@/interface/middlewares/pagination.middleware';

const router = express.Router();

// GET /notifications/user/:userId
router.get('/user/:userId', paginationMiddleware, notifyController.getNotificationsByUser);

// PATCH /notifications/user/:userId/read-all
router.patch('/user/:userId/read-all', notifyController.markAllAsRead);

// POST /notifications/send
router.post('/send', notifyController.sendNotification);

// PATCH /notifications/:id/read
router.patch('/:id/read', notifyController.markAsRead);

// DELETE /notifications/:id
router.delete('/:id', notifyController.deleteNotification);

export default router;

