import { ExamRepository } from '../../infrastructure/repositories/exam.repository';
import { StudentRepository } from '../../infrastructure/repositories/student.repository';
import { IExam, ExamType } from '../../infrastructure/database/models/exam.model';
import { UserModel } from '@/infrastructure/database/models/user.model';
import { StudentModel } from '@/infrastructure/database/models/student.model';
import { PaginationOptions } from '@/domain/types/pagination.types';
import { ExcelHelper } from '@/infrastructure/utils/excel.helper';
import { Response } from 'express';

// Service for exam domain operations
export class ExamService {
  private examRepository: ExamRepository;
  private studentRepository: StudentRepository;
  private excelHelper: ExcelHelper;

  constructor() {
    this.examRepository = new ExamRepository();
    this.studentRepository = new StudentRepository();
    this.excelHelper = new ExcelHelper();
  }

  async getAllExams(filters = {}, options: PaginationOptions = { page: 1, limit: 10 }, currentUser?: any) {
    return await this.examRepository.findAll(filters, options, currentUser);
  }

  async getExamById(id: string, currentUser?: any) {
    const exam = await this.examRepository.findById(id, currentUser);
    if (!exam) {
      throw new Error('Không tìm thấy kỳ thi hoặc bạn không có quyền truy cập');
    }
    return exam;
  }

  async createExam(data: Partial<IExam>) {
    return await this.examRepository.create(data);
  }

  async updateExam(id: string, data: Partial<IExam>) {
    return await this.examRepository.update(id, data);
  }

  async deleteExam(id: string) {
    return await this.examRepository.delete(id);
  }

  async getExamsByType(type: ExamType, options: PaginationOptions = { page: 1, limit: 10 }) {
    return await this.examRepository.findByType(type, options);
  }

  async getExamStudents(id: string, options: PaginationOptions = { page: 1, limit: 10 }, currentUser?: any) {
    return await this.examRepository.getStudents(id, options, currentUser);
  }

  async updateStudentResult(examId: string, studentId: string, result: string) {
    return await this.examRepository.updateStudentResult(examId, studentId, result);
  }

  async removeStudentFromExam(examId: string, studentId: string) {
    return await this.examRepository.removeStudentFromExam(examId, studentId);
  }

  async getExamsByStudent(studentId: string) {
    return await this.examRepository.findByStudentId(studentId);
  }

  async isAuthorized(examId: string, teacherId: string): Promise<boolean> {
    const exam = await this.examRepository.findById(examId);
    if (!exam) return false;

    // Strict Ownership Check: Is the teacher the creator of this exam batch/session?
    if (exam.teacher_id && exam.teacher_id.toString() === teacherId) return true;

    return false;
  }

  async exportExamsToExcel(res: Response, filters: any): Promise<void> {
    const { data } = await this.examRepository.findAll(filters, { page: 1, limit: 5000 });

    const { workbook, worksheet } = this.excelHelper.createWorkbook('Danh sách kỳ thi sát hạch');

    this.excelHelper.applyHeaderStyle(worksheet, [
      { header: 'Tên kỳ thi', key: 'name', width: 30 },
      { header: 'Loại thi', key: 'exam_type', width: 15 },
      { header: 'Sân thi', key: 'stadium', width: 20 },
      { header: 'Ngày thi', key: 'start_time', width: 18 },
      { header: 'Buổi', key: 'session', width: 10 },
      { header: 'Trạng thái', key: 'status', width: 15 },
      { header: 'Tổng thí sinh', key: 'total', width: 15 },
      { header: 'Số đậu', key: 'passed', width: 12 },
      { header: 'Số rớt', key: 'failed', width: 12 },
      { header: 'Kết quả chung', key: 'result', width: 15 },
    ]);

    data.forEach((exam: any) => {
      const results: any[] = exam.studentResults || [];
      const passedCount = results.filter((r: any) => r.result === 'pass').length;
      const failedCount = results.filter((r: any) => r.result === 'fail').length;

      const examTypeLabel = exam.exam_type === 'sat_hach' ? 'Sát hạch' : 'Tốt nghiệp';
      const resultLabel = exam.result === 'pass' ? 'Đậu' : exam.result === 'fail' ? 'Rớt' : 'Chưa có';

      worksheet.addRow({
        name: exam.name || '',
        exam_type: examTypeLabel,
        stadium: exam.stadium_id?.name || '',
        start_time: exam.start_time ? new Date(exam.start_time).toLocaleDateString('vi-VN') : '',
        session: exam.session || '',
        status: exam.status || '',
        total: exam.total_examinees ?? results.length,
        passed: passedCount,
        failed: failedCount,
        result: resultLabel,
      });
    });

    this.excelHelper.applyRowStyle(worksheet);
    await this.excelHelper.sendWorkbook(res, workbook, 'danh_sach_ky_thi');
  }

  async getExamStats(type: ExamType, currentUser?: any) {
    const [examStats, eligibleCount] = await Promise.all([
      this.examRepository.getStats(type, currentUser),
      currentUser?.role === 'teacher'
        ? this.studentRepository.countEligibleByTeacher(currentUser.id || currentUser._id)
        : this.studentRepository.countEligibleForGraduation(),
    ]);

    return {
      ...examStats,
      eligibleStudents: eligibleCount,
    };
  }

  async importResults(examId: string, filePath: string) {
    const results = await this.excelHelper.parseExamResults(filePath);
    let successCount = 0;
    let failCount = 0;

    for (const item of results) {
      try {
        // Find student by CCCD or Code
        const user = await UserModel.findOne({
          $or: [{ identity_card: item.cccd }, { username: item.studentCode }],
        })
          .select('_id')
          .lean()
          .exec();

        if (user) {
          const student = await StudentModel.findOne({ user_id: user._id }).select('_id').lean().exec();
          if (student) {
            await this.examRepository.updateStudentResult(examId, student._id.toString(), item.result);
            successCount++;
          } else {
            failCount++;
          }
        } else {
          failCount++;
        }
      } catch (err) {
        failCount++;
      }
    }

    return { successCount, failCount };
  }

  async getResultTemplate(res: Response) {
    return await this.excelHelper.getExamResultTemplate(res);
  }
}

