        is_received: p.is_received ? 'Đã nhận' : 'Chưa nhận',
        note: p.note || '',
      });
    });

    this.excelHelper.applyRowStyle(worksheet);
    await this.excelHelper.sendWorkbook(res, workbook, 'bao_cao_hoc_phi');
  }

  async exportPremiumFinancialReport(res: Response, filters: any, currentUser?: any): Promise<void> {
    // 1. Fetch data for all sheets
    const [stats, accountsRes, paymentsRes] = await Promise.all([
      this.paymentRepository.getStats(currentUser),
      this.paymentRepository.getTuitionAccounts(filters, { page: 1, limit: 10000 }, currentUser),
      this.paymentRepository.findAll(filters, { page: 1, limit: 10000 }, currentUser),
    ]);

    const accounts = accountsRes.data || [];
    const payments = paymentsRes.data || [];

    // --- WORKBOOK INITIALIZATION ---
    const { workbook, worksheet: summarySheet } = this.excelHelper.createWorkbook('1. Tổng quan');

    // --- SHEET 1: TỔNG QUAN (DASHBOARD STYLE) ---
    summarySheet.views = [{ state: 'frozen', ySplit: 0, xSplit: 0 }];
    summarySheet.properties.defaultRowHeight = 35;

    summarySheet.columns = [
      { header: 'CHỈ SỐ TÀI CHÍNH', key: 'label', width: 45 },
      { header: 'GIÁ TRỊ (VNĐ)', key: 'value', width: 35 },
    ];

    // Double-header or "Logo" area
    const logoRow = summarySheet.insertRow(1, ['BÁO CÁO TÀI CHÍNH TỔNG HỢP - HỆ THỐNG AHV', '']);
    summarySheet.mergeCells('A1:B1');
    logoRow.height = 50;
    logoRow.getCell(1).font = { bold: true, size: 20, color: { argb: 'FFFFFFFF' } };
    logoRow.getCell(1).fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF4F46E5' } };
    logoRow.getCell(1).alignment = { vertical: 'middle', horizontal: 'center' };

    summarySheet.addRows([
      { label: '👉 Tổng doanh thu dự kiến (Định mức học phí)', value: Number(stats.total_receivable || 0) },
      { label: '💰 Tổng số tiền đã thực thu (Tiền mặt/Chuyển khoản)', value: Number(stats.total_received || 0) },
      { label: '📉 Tổng công nợ còn lại (Cần thu hồi)', value: Number(stats.total_debt || 0) },
      { label: '👥 Số lượng học viên còn nợ', value: Number(stats.debtor_count || 0) },
      {
        label: '📈 Tỷ lệ hoàn thành thu nợ',
        value:
          stats.total_receivable > 0 ? ((stats.total_received / stats.total_receivable) * 100).toFixed(2) + '%' : '0%',
      },
    ]);

    // Style the Dashboard
    summarySheet.getColumn('value').numFmt = '#,##0';
    summarySheet.eachRow((row, rowNumber) => {
      if (rowNumber === 1) return;
      if (rowNumber === 2) {
        row.height = 40;
        row.eachCell((c) => {
          c.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF1E293B' } };
          c.font = { bold: true, color: { argb: 'FFFFFFFF' }, size: 12 };
          c.alignment = { vertical: 'middle', horizontal: 'center' };
        });
        return;
      }
      row.getCell(1).font = { bold: true, size: 12, color: { argb: 'FF4B5563' } };
      row.getCell(2).font = { bold: true, size: 14, color: { argb: rowNumber === 5 ? 'FFE11D48' : 'FF059669' } };
      row.getCell(1).alignment = { vertical: 'middle', indent: 2 };
      row.getCell(2).alignment = { vertical: 'middle', horizontal: 'right' };
      row.border = { bottom: { style: 'thin', color: { argb: 'FFE5E7EB' } } };
    });

    // --- HELPER: Create Grouped Summary Sheet ---
    const createSummarySheet = (name: string, data: any[], categoryLabel: string) => {
      const sheet = workbook.addWorksheet(name, { views: [{ state: 'frozen', ySplit: 1 }] });
      const cols = [
        { header: 'STT', key: 'stt', width: 8 },
        { header: categoryLabel, key: 'name', width: 35 },
        { header: 'Số lượng HV', key: 'count', width: 15 },
        { header: 'Tổng học phí', key: 'receivable', width: 22 },
        { header: 'Đã đóng', key: 'paid', width: 22 },
        { header: 'Công nợ', key: 'debt', width: 22 },
        { header: '% Thu hồi', key: 'ratio', width: 15 },
      ];
      this.excelHelper.applyHeaderStyle(sheet, cols);

      data.forEach((item, index) => {
        const ratio = item.receivable > 0 ? (item.paid / item.receivable) * 100 : 0;
        const row = sheet.addRow({
          stt: index + 1,
          name: item.name,
          count: item.count || 0,
          receivable: Number(item.receivable || 0),
          paid: Number(item.paid || 0),
          debt: Number(item.debt || 0),
          ratio: ratio.toFixed(1) + '%',
        });

        // Color coding for ratio
        const ratioCell = row.getCell('ratio');
        if (ratio >= 90) ratioCell.font = { color: { argb: 'FF059669' }, bold: true };
        else if (ratio < 60) ratioCell.font = { color: { argb: 'FFE11D48' }, bold: true };

        row.getCell('debt').font = { color: { argb: 'FFE11D48' }, bold: item.debt > 0 };
      });

      sheet.getColumn('receivable').numFmt = '#,##0';
      sheet.getColumn('paid').numFmt = '#,##0';
      sheet.getColumn('debt').numFmt = '#,##0';
      sheet.getColumn('count').alignment = { horizontal: 'center' };
      sheet.getColumn('ratio').alignment = { horizontal: 'center' };
      this.excelHelper.applyRowStyle(sheet);
    };

    // --- SHEET 2: THEO HẠNG BẰNG ---
    createSummarySheet('2. Theo Hạng bằng', stats.by_category || [], 'Hạng đào tạo');

    // --- SHEET 3: THEO KHÓA HỌC ---
    createSummarySheet('3. Theo Khóa học', stats.by_course || [], 'Tên khóa học');

    // --- SHEET 4: THEO TRUNG TÂM ---
    createSummarySheet('4. Theo Trung tâm', stats.by_region || [], 'Trung tâm / Tỉnh TP');

    // --- SHEET 5: CÔNG NỢ CHI TIẾT ---
    const accountSheet = workbook.addWorksheet('5. Công nợ chi tiết', { views: [{ state: 'frozen', ySplit: 1 }] });
    const accountCols = [
      { header: 'STT', key: 'stt', width: 8 },
      { header: 'Mã HV', key: 'code', width: 15 },
      { header: 'Họ tên', key: 'name', width: 25 },
      { header: 'Số điện thoại', key: 'phone', width: 18 },
      { header: 'Khóa học', key: 'course', width: 25 },
      { header: 'Hạng', key: 'rank', width: 10 },
      { header: 'Học phí', key: 'total', width: 18 },
      { header: 'Đã đóng', key: 'paid', width: 18 },
      { header: 'Còn nợ', key: 'debt', width: 18 },
      { header: 'Trạng thái', key: 'status', width: 15 },
    ];
    this.excelHelper.applyHeaderStyle(accountSheet, accountCols);

    accounts.forEach((acc: any, index: number) => {
      const cs = acc.course_student_id || {};
      const fee = Number(cs.fee || 0);
      const paid = Number(cs.paid_fee || 0);
      const debt = fee - paid;
      const row = accountSheet.addRow({
        stt: index + 1,
        code: (cs._id || '').toString().slice(-6).toUpperCase(),
        name: `${cs.student_id?.user_id?.last_name || ''} ${cs.student_id?.user_id?.first_name || ''}`.trim(),
        phone: cs.student_id?.user_id?.phone || '',
        course: cs.course_id?.name || '',
        rank: cs.course_id?.license_category_id?.name || 'B2',
        total: fee,
        paid: paid,
        debt: debt,
        status: debt <= 0 ? '✔️ Hoàn thành' : '⏳ Còn nợ',
      });
      if (debt > 0) row.getCell('debt').font = { color: { argb: 'FFE11D48' }, bold: true };
    });
    accountSheet.getColumn('total').numFmt = '#,##0';
    accountSheet.getColumn('paid').numFmt = '#,##0';
    accountSheet.getColumn('debt').numFmt = '#,##0';
    this.excelHelper.applyRowStyle(accountSheet);

    // --- SHEET 6: NHẬT KÝ GIAO DỊCH ---
    const logSheet = workbook.addWorksheet('6. Nhật ký giao dịch', { views: [{ state: 'frozen', ySplit: 1 }] });
    const logCols = [
      { header: 'Mã phiếu', key: 'id', width: 15 },
      { header: 'Ngày thu', key: 'date', width: 20 },
      { header: 'Học viên', key: 'student', width: 25 },
      { header: 'Nội dung', key: 'type', width: 20 },
      { header: 'Số tiền', key: 'amount', width: 18 },
      { header: 'Người thu', key: 'confirmer', width: 20 },
    ];
    this.excelHelper.applyHeaderStyle(logSheet, logCols);
    payments.forEach((p: any) => {
      const user = p.course_student_id?.student_id?.user_id || {};
      logSheet.addRow({
        id: (p._id || '').toString().slice(-8).toUpperCase(),
        date: p.payment_date ? new Date(p.payment_date) : new Date(),
        student: `${user.last_name || ''} ${user.first_name || ''}`.trim(),
        type: p.stage_name ? `Học phí (${p.stage_name})` : p.type === 'tuition_fee' ? 'Học phí' : 'Khác',
        amount: Number(p.received_fee || 0),
        confirmer: p.confirmer_id?.username || 'Hệ thống',
      });
    });
    logSheet.getColumn('date').numFmt = 'dd/mm/yyyy';
    logSheet.getColumn('amount').numFmt = '#,##0';
    this.excelHelper.applyRowStyle(logSheet);

    await this.excelHelper.sendWorkbook(
      res,
      workbook,
      `Bao_cao_tai_chinh_premium_${new Date().toISOString().split('T')[0]}`,
    );
  }

  async importPayments(filePath: string, confirmerId: string) {
    const data = await this.excelHelper.parseTuitionExcel(filePath);

    // eslint-disable-next-line @typescript-eslint/no-require-imports
    const { UserModel } = require('@/infrastructure/database/models/user.model');
    // eslint-disable-next-line @typescript-eslint/no-require-imports
    const { CourseStudentModel } = require('@/infrastructure/database/models/course_student.model');

    let successCount = 0;
    let failCount = 0;
    const errors: string[] = [];

    for (const item of data) {
      try {
        if (!item.cccd && !item.studentCode) {
          throw new Error('Thiếu CCCD hoặc Mã học viên');
        }

        // 1. Find User
        const user = await UserModel.findOne({
          $or: [{ identity_card: item.cccd }, { username: item.studentCode }],
        })
          .select('_id')
          .lean()
          .exec();

        if (!user) {
          throw new Error(`Không tìm thấy học viên với CCCD/Mã: ${item.cccd || item.studentCode}`);
        }

        // 2. Find StudentInfo ID from User
        // eslint-disable-next-line @typescript-eslint/no-require-imports
        const { StudentModel } = require('@/infrastructure/database/models/student.model');
        const student = await StudentModel.findOne({ user_id: user._id }).select('_id').lean().exec();

        if (!student) {
          throw new Error(`Học viên chưa có hồ sơ StudentInfo (User: ${user._id})`);
        }

        // 3. Find most recent Enrollment (CourseStudent)
        const enrollment = await CourseStudentModel.findOne({
          student_id: student._id,
          status: 'unfinished',
        })
          .sort({ created_at: -1 })
          .select('_id fee paid_fee')
          .lean()
          .exec();

        if (!enrollment) {
          throw new Error(`Học viên ${item.fullName} hiện không trong khóa học nào hoặc đã hoàn thành.`);
        }

        // 4. Generate Receipt ID if missing
        let receiptCode = item.note;
        if (!receiptCode) {
          receiptCode = await this.paymentRepository.getNextReceiptCode();
        }

        // 5. Create Payment
        await this.paymentRepository.create({
          course_student_id: enrollment._id,
          payment_date: item.date,
          received_fee: item.amount,
          type: 'tuition_fee' as any,
          stage_name: item.stageName,
          note: receiptCode,
          confirmer_id: confirmerId as any,
          is_received: true,
        });

        successCount++;
      } catch (err: any) {
        failCount++;
        errors.push(`${item.fullName || 'N/A'}: ${err.message}`);
      }
    }

    return { successCount, failCount, errors };
  }

  async getImportTemplate(res: Response) {
    return await this.excelHelper.getTuitionImportTemplate(res);
  }
}

