import mongoose from 'mongoose';
import { StadiumRepository } from '@/infrastructure/repositories/stadium.repository';

export class StadiumService {
  private stadiumRepository: StadiumRepository;

  constructor() {
    this.stadiumRepository = new StadiumRepository();
  }

  async getAllStadiums(filters: any, pagination: any) {
    return this.stadiumRepository.findAll(filters, pagination);
  }

  async getStadiumById(id: string) {
    return this.stadiumRepository.findById(id);
  }

  async createStadium(data: any) {
    // If locate is empty but region_id is present, try to populate it with region info
    if (!data.locate && data.region_id) {
      const city = await mongoose.model('Cities').findById(data.region_id);
      if (city) {
        data.locate = (city as any).name;
      }
    }
    return this.stadiumRepository.create(data);
  }

  async updateStadium(id: string, data: any) {
    return this.stadiumRepository.update(id, data);
  }

  async deleteStadium(id: string) {
    return this.stadiumRepository.delete(id);
  }
}

