import { SupportRequestRepository } from '../../infrastructure/repositories/support_request.repository';

export class SupportRequestService {
  private repository: SupportRequestRepository;

  constructor() {
    this.repository = new SupportRequestRepository();
  }

  async getAllRequests(filters: any) {
    return this.repository.findAll(filters);
  }

  async getRequestById(id: string) {
    const request = await this.repository.findById(id);
    if (!request) {
      throw new Error('Không tìm thấy yêu cầu hỗ trợ này.');
    }
    return request;
  }

  async createRequest(data: any, userId: string, userRole: string) {
    // Inject sender information automatically
    const payload = {
      ...data,
      sender_id: userId,
      sender_role: userRole,
      status: 'Mới' // Always force new status on creation
    };
    return this.repository.create(payload);
  }

  async updateRequest(id: string, updateData: any, adminId?: string) {
    const existing = await this.getRequestById(id);

    // If status is transitioning to Hoàn thành, track the resolver
    if (updateData.status === 'Hoàn thành' && existing.status !== 'Hoàn thành') {
      updateData.resolved_by = adminId;
      updateData.resolved_at = new Date();
    }

    const updated = await this.repository.update(id, updateData);
    if (!updated) {
       throw new Error('Lỗi cập nhật. Không thể lưu dữ liệu.');
    }
    return updated;
  }

  async deleteRequest(id: string) {
    const deleted = await this.repository.delete(id);
    if (!deleted) {
      throw new Error('Không tìm thấy dữ liệu để xóa.');
    }
    return true;
  }
}

